import React from 'react';

export const getStatusLabel = (status) => {
  const map = { PENDING: 'Chờ xử lý', ASSIGNED: 'Đã phân công', IN_PROGRESS: 'Đang hỗ trợ', RESOLVED: 'Đã hoàn thành', CANCELLED: 'Đã hủy' };
  return map[status] || status;
};

export const getStatusStyle = (status) => {
  const styles = {
    PENDING: { background: '#FEF3C7', color: '#B45309' },
    ASSIGNED: { background: '#DBEAFE', color: '#1D4ED8' },
    IN_PROGRESS: { background: '#E0F2FE', color: '#0369A1' },
    RESOLVED: { background: '#DCFCE7', color: '#15803D' },
    CANCELLED: { background: '#FEE2E2', color: '#B91C1C' }
  };
  return styles[status] || { background: '#E2E8F0', color: '#475569' };
};

const SupportCard = ({ req, isMine, onClick }) => (
  <div onClick={() => onClick(req)} style={{ background: '#fff', borderRadius: '16px', padding: '24px', border: '1px solid #E2E8F0', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', cursor: 'pointer' }}>
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
      <h3 style={{ margin: 0, fontSize: '1.25rem', fontWeight: '800', color: '#1E293B' }}>{req.requestType}</h3>
      <span style={{ ...getStatusStyle(req.status), padding: '6px 12px', borderRadius: '999px', fontSize: '0.8rem', fontWeight: '700' }}>
        {getStatusLabel(req.status)}
      </span>
    </div>
    <div style={{ color: '#475569', fontSize: '0.95rem', minHeight: '48px', marginBottom: '16px', lineHeight: 1.5 }}>
      {req.description?.length > 80 ? req.description.substring(0, 80) + '...' : req.description}
    </div>
    <div style={{ display: 'flex', gap: '16px', color: '#64748B', fontSize: '0.9rem', marginBottom: '12px' }}>
      <span>👥 {req.numberOfPeople} người</span>
      <span>📅 {req.createdAt ? new Date(req.createdAt).toLocaleDateString('vi-VN') : ''}</span>
    </div>
    <div style={{ color: '#64748B', fontSize: '0.9rem', marginBottom: isMine ? '12px' : '0' }}>📍 {req.address || 'Đang cập nhật'}</div>
    {isMine && <div style={{ color: '#2563EB', fontWeight: '700', fontSize: '0.85rem' }}>YÊU CẦU CỦA BẠN</div>}
  </div>
);
export default SupportCard;
